SELECT COUNT(*) FROM MEMBER_TBL M LEFT JOIN NATIVES_TBL N ON M.MEMBER_ID = N.MEMBER_ID
M.MEMBER_ID LIKE CONCAT('%', #{keyword}, '%')
AND M.MEMBER_STATUS = #{memberStatus}

SELECT M.MEMBER_NO AS memberNo, M.MEMBER_ID AS memberId, M.MEMBER_NAME AS memberName, M.MEMBER_EMAIL AS memberEmail, M.MEMBER_NICKNAME AS memberNickname, M.MEMBER_THUMB AS memberThumb, M.MEMBER_STATUS AS memberStatus, M.ADMIN AS admin, DATE_FORMAT(M.ENROLL_DATE, '%Y-%m-%d') AS enrollDate, N.REGION AS region FROM MEMBER_TBL M LEFT JOIN NATIVES_TBL N ON M.MEMBER_ID = N.MEMBER_ID
M.MEMBER_ID LIKE CONCAT('%', #{keyword}, '%')
AND M.MEMBER_STATUS = #{memberStatus}
ORDER BY M.MEMBER_NAME DESC
ORDER BY M.MEMBER_NAME ASC
LIMIT #{offset}, #{size}

